import React from 'react';

function Toolbox({ data }) {
  const toolbox = data && data.length > 0 && data.some((tool) => tool.image)
    ? data
    : [
        { id: 1, name: 'Figma', image: '/Figma.png' },
        { id: 2, name: 'VS Code', image: '/VSCode.png' },
        { id: 3, name: 'ChatGPT', image: '/Chatgpt.png' },
        { id: 4, name: 'Photoshop', image: '/Photoshop.png' },
        { id: 5, name: 'Canva', image: '/Canva.png' },
        { id: 6, name: 'IntelliJ', image: '/IntelliJ_IDEA.png' },
        { id: 7, name: 'MongoDB', image: '/MongoDB.png' }
      ];

  return (
    <section id="toolbox" className="py-12 md:py-16 bg-[#f6f1e7]">
      <div className="max-w-7xl mx-auto px-4">
        <div className="mb-8 md:mb-10">
          <p className="text-[10px] uppercase tracking-[0.4em] text-[#7b7367] font-semibold mb-3">
            Working System
          </p>
          <h2
            className="text-3xl md:text-5xl text-[#1d1c19]"
            style={{ fontFamily: '"Playfair Display", "Times New Roman", serif', fontWeight: 700 }}
          >
            Toolbox
          </h2>
        </div>

        <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-7 gap-3 md:gap-4">
          {toolbox.map((tool) => (
            <div
              key={tool.id}
              className="flex flex-col items-center justify-center gap-3 group p-4 rounded-2xl border border-[#ddd3c5] bg-white hover:bg-[#fbf7f0] transition-all duration-300 shadow-[0_10px_24px_rgba(17,17,17,0.05)]"
            >
              <div className="w-12 h-12 md:w-14 md:h-14 flex items-center justify-center overflow-hidden">
                {tool.image ? (
                  <img
                    src={tool.image}
                    alt={tool.name}
                    className="w-full h-full object-contain"
                  />
                ) : (
                  <span className="text-3xl font-bold text-[#1f1d1a]">{tool.icon}</span>
                )}
              </div>
              <p className="text-[10px] uppercase tracking-[0.2em] text-[#7f776b] font-semibold text-center">{tool.name}</p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

export default Toolbox;
